import json
import sys

def validate_config():
    """Validate that config.json exists and has required fields"""
    try:
        with open('config.json', 'r') as f:
            config = json.load(f)

        # Check required fields
        required_fields = ['pagasa_url', 'email_config', 'check_interval_seconds', 'notification_enabled']
        missing_fields = []

        for field in required_fields:
            if field not in config:
                missing_fields.append(field)

        if missing_fields:
            print(f"❌ Missing required fields in config.json: {missing_fields}")
            return False

        # Check email config
        email_config = config['email_config']
        email_required = ['smtp_server', 'smtp_port', 'sender_email', 'sender_password', 'recipient_email']
        missing_email = []

        for field in email_required:
            if field not in email_config:
                missing_email.append(field)

        if missing_email:
            print(f"❌ Missing required email fields: {missing_email}")
            return False

        print("✅ Configuration file is valid")
        return True

    except FileNotFoundError:
        print("❌ config.json file not found")
        return False
    except json.JSONDecodeError as e:
        print(f"❌ Invalid JSON in config.json: {e}")
        return False
    except Exception as e:
        print(f"❌ Error validating config: {e}")
        return False

if __name__ == "__main__":
    success = validate_config()
    sys.exit(0 if success else 1)

import requests
import json
from datetime import datetime

# Simple status checker for PAGASA typhoon monitoring

def check_pagasa_status():
    """Check if PAGASA website is accessible"""
    try:
        headers = {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
        }
        response = requests.get('https://www.pagasa.dost.gov.ph/', headers=headers, timeout=10)

        if response.status_code == 200:
            print(f"✅ PAGASA website is accessible")
            print(f"   Status code: {response.status_code}")
            print(f"   Response time: {response.elapsed.total_seconds():.2f}s")

            # Check for typhoon-related content
            content = response.text.lower()
            keywords = ['typhoon', 'tropical cyclone', 'bulletin', 'storm']
            found_keywords = [kw for kw in keywords if kw in content]

            if found_keywords:
                print(f"   Typhoon keywords found: {', '.join(found_keywords)}")
            else:
                print("   No typhoon keywords found in homepage")

        else:
            print(f"❌ PAGASA website returned status code: {response.status_code}")

    except requests.exceptions.RequestException as e:
        print(f"❌ Error connecting to PAGASA website: {e}")

if __name__ == "__main__":
    print(f"PAGASA Status Check - {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
    print("=" * 50)
    check_pagasa_status()
